import{_ as e,c as a,a as i,o as n}from"./app-CEcM0piI.js";const l={};function d(p,s){return n(),a("div",null,s[0]||(s[0]=[i(`<p>![[Pasted image 20250125125709.png]] 在每个生命周期都提供了两个函数一个是开始之前一个是完成之后, 要重写这些函数需要在vue对象中</p><h1 id="脚手架工具" tabindex="-1"><a class="header-anchor" href="#脚手架工具"><span>脚手架工具</span></a></h1><p>VueCLI是Vue官方提供的一个全局命令工具。 可以帮助我们快速创建一个开发Vue项目的标准化基础架子。【集成了webpack配置】</p><ol><li>全局安装：</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm i @vue/cli -g</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>查看Vue版本：</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>vue --version</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>3.创建项目架子：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>vue create project-name（项目名-不能用中文)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>4.启动项目：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm run servee（找package.json)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="项目文件" tabindex="-1"><a class="header-anchor" href="#项目文件"><span>项目文件</span></a></h3><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>vue-project/  </span></span>
<span class="line"><span>├── node_modules/      第三方包文件夹</span></span>
<span class="line"><span>├── public/            放html文件的地方</span></span>
<span class="line"><span>│   ├── favicon.ico    网站图标</span></span>
<span class="line"><span>│   └── index.html     index.html模板文件 </span></span>
<span class="line"><span>├── src/               源代码目录-&gt;存放代码的文件夹</span></span>
<span class="line"><span>│   ├── assets/        静态资源目录-&gt;存放图片,字体等</span></span>
<span class="line"><span>│   ├── components/    组件目录-&gt;存放通用组件</span></span>
<span class="line"><span>│   ├── views/         路由切换相关</span></span>
<span class="line"><span>│   ├── router/  </span></span>
<span class="line"><span>│   ├── store/  </span></span>
<span class="line"><span>│   ├── App.vue        App根组件-&gt;项目运行看到的内容</span></span>
<span class="line"><span>│   ├── main.js        入口文件-&gt;打包或 运行,第一个执行的文件</span></span>
<span class="line"><span>│   └── env.js  </span></span>
<span class="line"><span>├── tests/  </span></span>
<span class="line"><span>│   ├── unit/  </span></span>
<span class="line"><span>│   └── e2e/  </span></span>
<span class="line"><span>├── .gitignore         git忽略文件</span></span>
<span class="line"><span>├── babel.config.js    babel配置文件</span></span>
<span class="line"><span>├── jsconfig.json      js配置文件</span></span>
<span class="line"><span>├── package.json       项目配置文件-&gt;包含项目名,版本号,scripts,依赖包等</span></span>
<span class="line"><span>├── README.md          项目说明文档</span></span>
<span class="line"><span>├── vue.config.js      vue-cli配置文件</span></span>
<span class="line"><span>└── yarn.lock          yarn锁文件,由yarn自动生成的,锁定安装版本</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>components和views文件夹都是存放组件的,将他们区分开来是为了更易维护</p><ul><li>views文件夹 页面组件-页面展示－配合路由用</li><li>components文件夹 复用组件－展示数据－常用于复用</li></ul><h3 id="组件化开发" tabindex="-1"><a class="header-anchor" href="#组件化开发"><span>组件化开发</span></a></h3><p>组件化：一个页面可以拆分成一个个组件，每个组件有着自己独立的结构、样式、行为 好处：便于维护，利于复用→提升开发效率。</p><p>在.vue文件中<code>&lt;template&gt;</code>是结构用于写html代码,<code>&lt;style&gt;</code>是样式用于写css代码,<code>&lt;script&gt;</code>是行为用于写js代码 在vue2的结构中只允许有一个div根元素</p><p>组件命名 设置组件后默认是以文件名作为组件名的,可以使用name属性手动指定组件名</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default{</span></span>
<span class="line"><span>	name:&quot;Componet&quot;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="样式" tabindex="-1"><a class="header-anchor" href="#样式"><span>样式</span></a></h3><p>样式内默认是css语法,如果要写sass或者less等语法需要下载以来并设置</p><ol><li>下载依赖</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm install less less-loader --save-dev -g</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>设置</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;style lang=&quot;less&quot;&gt;</span></span>
<span class="line"><span>&lt;/style&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="行为" tabindex="-1"><a class="header-anchor" href="#行为"><span>行为</span></a></h3><p><strong>export default</strong> 导出当前组件的配置项,如:data,methods,computed,watch,生命周期构造函数等</p><h2 id="普通组件" tabindex="-1"><a class="header-anchor" href="#普通组件"><span>普通组件</span></a></h2><p>组件注册的两种方式：</p><ol><li>局部注册：只能在注册的组件内使用</li><li>全局注册：所有组件内都能使用</li></ol><h4 id="局部注册" tabindex="-1"><a class="header-anchor" href="#局部注册"><span>局部注册</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//导入需要注册的组件</span></span>
<span class="line"><span>import 组件对象 from &#39;.vue文件路径&#39;</span></span>
<span class="line"><span>import HmHeader from &#39;./components/HmHeader&#39;</span></span>
<span class="line"><span>export default {</span></span>
<span class="line"><span>	//局部注册</span></span>
<span class="line"><span>	components:{</span></span>
<span class="line"><span>		//&#39;组件名&#39;：组件对象，</span></span>
<span class="line"><span>		HmHeader:HmHeader</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当注册好组件后,使用时当成html标签使用<code>&lt;组件名&gt;&lt;/组件名&gt;</code></p><h4 id="全局注册" tabindex="-1"><a class="header-anchor" href="#全局注册"><span>全局注册</span></a></h4><p>全局注册代码需要写在main.js中</p><div class="language-main.js line-numbers-mode" data-highlighter="shiki" data-ext="main.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//导入需要全局注册的组件</span></span>
<span class="line"><span>import HmButton from &#39;./components/HmButton&#39;</span></span>
<span class="line"><span>// 调用 Vue.component 进行全局注册</span></span>
<span class="line"><span>// Vue.component（&#39;组件名&#39;，组件对象）</span></span>
<span class="line"><span>Vue.component(&#39;HmButton&#39;, HmButton)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="样式冲突" tabindex="-1"><a class="header-anchor" href="#样式冲突"><span>样式冲突</span></a></h2><h3 id="局部样式" tabindex="-1"><a class="header-anchor" href="#局部样式"><span>局部样式</span></a></h3><p>默认情况：写在组件中的样式会全局生效→因此很容易造成多个组件之间的样式冲突问题。</p><ol><li>全局样式：默认组件中的样式会作用到全局</li><li>局部样式：可以给组件加上scoped属性，可以让样式只作用于当前组件</li></ol><p>默认的style样式会作用于全局 给style样式加上scoped属性后样式就会只作用域当前组件</p><p><strong>原理:</strong> 给样式加上scoped属性后当前组件中的所有元素都会被添加上一个<code>data-v-hash值</code>的自定义属性,通过这个属性来区分不同组件 在css选择器上也会被自动处理,添加上属性选择器<code>div[data-v-hash值]</code></p><h3 id="data函数" tabindex="-1"><a class="header-anchor" href="#data函数"><span>data函数</span></a></h3><p>一个组件的 data 选项必须是一个函数。→保证每个组件实例，维护独立的一份数据对象。 每次创建新的组件实例，都会新执行一次data函数，得到一个新对象，</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>data(){</span></span>
<span class="line"><span>	return{</span></span>
<span class="line"><span>		count:10</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>用法和<code>data:</code>设置数据完全一致</p><h1 id="组件间通信" tabindex="-1"><a class="header-anchor" href="#组件间通信"><span>组件间通信</span></a></h1><h2 id="父子间传递数据" tabindex="-1"><a class="header-anchor" href="#父子间传递数据"><span>父子间传递数据</span></a></h2><h3 id="props" tabindex="-1"><a class="header-anchor" href="#props"><span>props</span></a></h3><p>用于父元素给它的子元素传递数据</p><div class="language-parent.vue line-numbers-mode" data-highlighter="shiki" data-ext="parent.vue" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;son :title=&quot;myTitle&quot;&gt;&lt;/son&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export default{</span></span>
<span class="line"><span>	data(){</span></span>
<span class="line"><span>		return{</span></span>
<span class="line"><span>			myTitle:&quot;hello world&quot;</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>子组件在接受数据时需要使用props来接受,且必须是一个数组对象</p><div class="language-son.vue line-numbers-mode" data-highlighter="shiki" data-ext="son.vue" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div&gt;</span></span>
<span class="line"><span>	{{title}}</span></span>
<span class="line"><span>&lt;/div&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export default{</span></span>
<span class="line"><span>	props:[&#39;title&#39;]</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="校验" tabindex="-1"><a class="header-anchor" href="#校验"><span>校验</span></a></h4><p>由于vue是弱类型,所以在传递的数据不符合要求的时候也有可能不报错 可以对props设置多种校验</p><p>设置校验的props接收的就不是一个数组参数了,而是一个对象</p><ol><li>类型校验</li><li>非空校验</li><li>默认值</li><li>自定义校验</li></ol><p>当传递的数据不符合设定的校验规则时就会报错</p><p><strong>基础写法</strong> 类型校验是常用的,所以在只指定类型校验的情况时就可以简写</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default{</span></span>
<span class="line"><span>	props:{</span></span>
<span class="line"><span>		w:Number  //设置w类型必须是一个数字类型</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>完整写法</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default{</span></span>
<span class="line"><span>	props:{</span></span>
<span class="line"><span>		w:{</span></span>
<span class="line"><span>			type:Number,      //类型校验</span></span>
<span class="line"><span>			required:true,    //非空校验</span></span>
<span class="line"><span>			default:10,       //默认值</span></span>
<span class="line"><span>			validator(){}     //自定义校验. 返回值是一个布尔类型,返回true通过校验,false未通过校验</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="emit" tabindex="-1"><a class="header-anchor" href="#emit"><span>$emit</span></a></h3><p>$emit用于子元素向它的父元素传递数据</p><div class="language-son.vue line-numbers-mode" data-highlighter="shiki" data-ext="son.vue" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div&gt;</span></span>
<span class="line"><span>	&lt;button @click=&quot;func&quot;&gt;&lt;/button&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export default{</span></span>
<span class="line"><span>	method:{</span></span>
<span class="line"><span>		func(){</span></span>
<span class="line"><span>			$emit(&quot;val&quot;,&quot;nihao&quot;)</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>父元素需要监听子元素发送数据的key,并设定监听函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;son @val=&quot;handle&quot;&gt;&lt;/son&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export default{</span></span>
<span class="line"><span>	methods:{</span></span>
<span class="line"><span>		handle(newValue){}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="sync" tabindex="-1"><a class="header-anchor" href="#sync"><span>.sync</span></a></h3><p>可以实现子组件与父组件数据的双向绑定，简化代码 prop属性名，可以自定义，非固定为value</p><p>本质就是：属性名和@update:属性名合写</p><p><strong>父组件发送数据</strong> 父组件设置发送数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;BaseDialog :visible.sync=&quot;isShow&quot;&gt;&lt;/BaseDialog&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>子组件接受数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>props:{</span></span>
<span class="line"><span>	visible:Boolean</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>子组件发送数据</strong> 父组件设置监听</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;BaseDialog :visible=&quot;isShow&quot; @update:visible=&quot;isShow =$event&quot;/&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>子组件发送数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>$emit(&#39;update:visible&#39;,false)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="非父子通信" tabindex="-1"><a class="header-anchor" href="#非父子通信"><span>非父子通信</span></a></h2><h3 id="event-bus事件总线" tabindex="-1"><a class="header-anchor" href="#event-bus事件总线"><span>event bus事件总线</span></a></h3><p>创建一个都能访问到的事件总线(空的vue实例)</p><div class="language-app.vue line-numbers-mode" data-highlighter="shiki" data-ext="app.vue" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const Bus=new Vue();</span></span>
<span class="line"><span>export defalult Bus;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>在接收方设置监听</p><div class="language-a.vue line-numbers-mode" data-highlighter="shiki" data-ext="a.vue" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import Bus from &#39;../utils/EventBus&#39;</span></span>
<span class="line"><span>export default{</span></span>
<span class="line"><span>	created(){</span></span>
<span class="line"><span>	//监听发送消息事件</span></span>
<span class="line"><span>	Bus.$on(&#39;sendMsg&#39;,(msg)=&gt;{</span></span>
<span class="line"><span>		console.log(msg)</span></span>
<span class="line"><span>	})</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在发送方发送数据</p><div class="language-b.vue line-numbers-mode" data-highlighter="shiki" data-ext="b.vue" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import Bus from &#39;../utils/EventBus&#39;</span></span>
<span class="line"><span>export default{</span></span>
<span class="line"><span>	methods:{</span></span>
<span class="line"><span>		Bus.$emit(&#39;sendMsg&#39;,&#39;这是一条消息&#39;)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="provide-inject" tabindex="-1"><a class="header-anchor" href="#provide-inject"><span>provide&amp;inject</span></a></h3><p>跨层级共享数据</p><p>用于子孙元素通信,props只能用于父子间传输数据</p><p>父组件发送数据写在provide函数的返回值中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default {</span></span>
<span class="line"><span>	provide(){</span></span>
<span class="line"><span>		return {</span></span>
<span class="line"><span>			//普通类型【非响应式】</span></span>
<span class="line"><span>			color: this.color,</span></span>
<span class="line"><span>			//复杂类型【响应式】</span></span>
<span class="line"><span>			userInfo: this.userInfo</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>子孙组件取值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default{</span></span>
<span class="line"><span>	inject:[&#39;color&#39;,&#39;userInfo&#39;],</span></span>
<span class="line"><span>	created(){</span></span>
<span class="line"><span>		console.log(this.color, this.userInfo)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="v-model通信" tabindex="-1"><a class="header-anchor" href="#v-model通信"><span>v-model通信</span></a></h3><p>v-model本质上是一个语法糖。例如应用在输入框上，就是value属性和input事件的合写。</p><p>使用v-model监听输入事件,接着再使用props获取数据</p><h1 id="获取组件" tabindex="-1"><a class="header-anchor" href="#获取组件"><span>获取组件</span></a></h1><h2 id="ref和-ref" tabindex="-1"><a class="header-anchor" href="#ref和-ref"><span>ref和$ref</span></a></h2><p>利用ref和$refs可以用于获取dom元素，或组件实例 查找范围→ 当前组件内 (更精确稳定)</p><ol><li>目标标签－添加ref属性</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div ref=&quot;chartRef&quot;&gt;我是渲染图表的容器&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>恰当时机，通过this.$refs.xxx,获取目标标签</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mounted{</span></span>
<span class="line"><span>	console.log(this.$refs.chartRef)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>也可以获取组件中得到函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>$refs.chartRef.func()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="异步dom更新" tabindex="-1"><a class="header-anchor" href="#异步dom更新"><span>异步dom更新</span></a></h1><p>vue更新dom是异步的,如果在更新完成前获取其中的数据可能会得到undefined 可以使用<code>$nextTick</code>函数,这个函数会在dom更新后才触发</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>this.$nextTick(()=&gt;{</span></span>
<span class="line"><span>	this.$refs.inp.focus()</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>此生命周期对应的是updated,但updated范围太大,整个页面的dom更新都会调用它,<code>$nextTick</code>是当前组件的</p>`,110)]))}const r=e(l,[["render",d]]),c=JSON.parse('{"path":"/front/vue/2/","title":"2 工程化","lang":"zh-CN","frontmatter":{"title":"2 工程化","createTime":"2025/05/01 12:27:28","permalink":"/front/vue/2/"},"readingTime":{"minutes":6.6,"words":1981},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/vue/2 工程化.md","headers":[]}');export{r as comp,c as data};
